module top_module(
  input clk,
  input rst_n,
  input [7:0] a,
  input [7:0] b,
  input [1:0] op,
  output [7:0] result,
  output valid
);reg [8:0] unused_sum;
  assign result = unused_sum[7:0];
  assign valid = (unused_sum[8] == 1'b0);

  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      unused_sum <= 9'b0;
    end
    else begin
      case (op)
        2'b00: unused_sum <= a + b;
        2'b01: unused_sum <= a - b;
        default: unused_sum <= 9'b0;
      endcase
    end
  end

endmodule
